mapper.insert:
insert into upstream_system_sync_request(
    request_no, connection_code, trigger_source, mode, requested_sync_types,
    status, submitted_by, submitted_time, task_count, create_time, remark
) values (
    #{requestNo}, #{connectionCode}, #{triggerSource}, #{mode}, #{requestedSyncTypes},
    #{status}, #{submittedBy}, #{submittedTime}, #{taskCount}, sysdate(), #{remark}
)

insert into upstream_system_sync_task(
    request_no, sync_batch_id, connection_code, sync_type, mode, trigger_source,
    status, priority, payload_redacted, attempt_count, max_attempts,
    next_attempt_time, deadline_at, trace_id, sys_job_invoke_target, create_time, remark
) values (
    #{requestNo}, #{syncBatchId}, #{connectionCode}, #{syncType}, #{mode}, #{triggerSource},
    #{status}, #{priority}, #{payloadRedacted}, coalesce(#{attemptCount}, 0), coalesce(#{maxAttempts}, 1),
    #{nextAttemptTime}, #{deadlineAt}, #{traceId}, #{sysJobInvokeTarget}, sysdate(), #{remark}
)

mapper.select:
select *
from upstream_system_sync_task
where connection_code = #{connectionCode}
  and task_id = #{taskId}
limit 1
